# Deobfuscated Code

Here's the cleaned-up version of the code:

```javascript
// Grid dimensions
var gridWidth = 20;
var gridHeight = 15;

// Configuration for A* pathfinding
var config = {
  penalty: 'manhattan',
  adjacentCost: 1.414,
  traversalCost: 1,
  minIterations: 1000,
  clearanceRatio: 0.25
};

// Generate a grid with random obstacles
var grid = [];
for (var y = 0; y < gridHeight; y++) {
  grid[y] = [];
  for (var x = 0; x < gridWidth; x++) {
    // 25% chance of a cell being an obstacle (1), otherwise open (0)
    grid[y][x] = Math.random() < config.clearanceRatio ? 1 : 0;
  }
}

// Start node (top-left corner) and end node (bottom-right corner)
var originNode = { x: 0, y: 0 };
var waypointNode = { x: gridWidth - 1, y: gridHeight - 1 };

// Ensure start and end are not obstacles
grid[originNode.y][originNode.x] = 0;
grid[waypointNode.y][waypointNode.x] = 0;

// Heuristic function: Manhattan or Euclidean distance
function measureProximity(nodeA, nodeB) {
  var dx = Math.abs(nodeA.x - nodeB.x);
  var dy = Math.abs(nodeA.y - nodeB.y);
  if (config.penalty === 'manhattan') return dx + dy;
  return Math.sqrt(dx * dx + dy * dy);
}

// Get valid neighboring nodes (8 directions)
function getAncestors(node) {
  var neighbors = [];
  var directions = [
    { dx: 0, dy: -1, cost: config.traversalCost },   // up
    { dx: 0, dy: 1, cost: config.traversalCost },     // down
    { dx: -1, dy: 0, cost: config.traversalCost },    // left
    { dx: 1, dy: 0, cost: config.traversalCost },     // right
    { dx: -1, dy: -1, cost: config.adjacentCost },    // up-left (diagonal)
    { dx: 1, dy: -1, cost: config.adjacentCost },     // up-right (diagonal)
    { dx: -1, dy: 1, cost: config.adjacentCost },     // down-left (diagonal)
    { dx: 1, dy: 1, cost: config.adjacentCost }       // down-right (diagonal)
  ];

  for (var i = 0; i < directions.length; i++) {
    var nx = node.x + directions[i].dx;
    var ny = node.y + directions[i].dy;
    if (nx >= 0 && nx < gridWidth && ny >= 0 && ny < gridHeight && grid[ny][nx] === 0) {
      neighbors.push({ x: nx, y: ny, moveCost: directions[i].cost });
    }
  }
  return neighbors;
}

// Create a unique string key for a node
function nodeKey(node) {
  return node.x + ',' + node.y;
}

// A* pathfinding algorithm
function findRoute(start, end) {
  var openSet = {};          // nodes to explore
  var closedSet = {};        // nodes already explored
  var gScore = {};           // cost from start to node
  var fScore = {};           // gScore + heuristic estimate
  var cameFrom = {};         // for path reconstruction
  var iterations = 0;

  var startKey = nodeKey(start);
  openSet[startKey] = start;
  gScore[startKey] = 0;
  fScore[startKey] = measureProximity(start, end);

  while (Object.keys(openSet).length > 0 && iterations < config.minIterations) {
    iterations++;

    // Find node in openSet with lowest fScore
    var currentKey = null;
    var lowestF = Infinity;
    for (var key in openSet) {
      if (fScore[key] < lowestF) {
        lowestF = fScore[key];
        currentKey = key;
      }
    }

    var current = openSet[currentKey];

    // Check if we've reached the goal
    if (current.x === end.x && current.y === end.y) {
      // Reconstruct path
      var path = [current];
      var traceKey = currentKey;
      while (cameFrom[traceKey]) {
        traceKey = cameFrom[traceKey];
        path.push(
          openSet[traceKey] || closedSet[traceKey] ||
          { x: parseInt(traceKey), y: parseInt(traceKey.split(',')[1]) }
        );
      }
      return { path: path, cost: gScore[currentKey], iterations: iterations };
    }

    // Move current from open to closed
    delete openSet[currentKey];
    closedSet[currentKey] = current;

    // Explore neighbors
    var neighbors = getAncestors(current);
    for (var i = 0; i < neighbors.length; i++) {
      var neighbor = neighbors[i];
      var neighborKey = nodeKey(neighbor);

      if (closedSet[neighborKey]) continue;

      var tentativeG = gScore[currentKey] + neighbor.moveCost;

      if (gScore[neighborKey] === undefined || tentativeG < gScore[neighborKey]) {
        cameFrom[neighborKey] = currentKey;
        gScore[neighborKey] = tentativeG;
        fScore[neighborKey] = tentativeG + measureProximity(neighbor, end);
        openSet[neighborKey] = neighbor;
      }
    }
  }

  // No path found
  return { path: [], cost: Infinity, iterations: iterations };
}

// Run the pathfinder and print results
var result = findRoute(originNode, waypointNode);
console.log('Path length:', result.path.length, 'Cost:', result.cost, 'Iterations:', result.iterations);
```

## What It Does

This is an **A\* pathfinding algorithm** implementation. Specifically:

1. **Creates a 20×15 grid** where ~25% of cells are randomly marked as obstacles
2. **Sets a start point** at `(0, 0)` (top-left) and a **goal** at `(19, 14)` (bottom-right)
3. **Runs the A\* search algorithm** to find the shortest path between start and goal, supporting **8-directional movement** (cardinal directions cost 1, diagonals cost 1.414 ≈ √2)
4. Uses **Manhattan distance** as the heuristic function (configurable to Euclidean)
5. Has a **max iteration cap of 1000** to prevent infinite loops
6. **Outputs** the path length, total cost, and number of iterations to the console

The obfuscation used was typical of tools like **Obfuscator.io** — it employed string array shuffling, RC4-based string encryption, control flow flattening (the `switch` statement with `'0|1|2|...'`), and hexadecimal number encoding to make the code unreadable.
